import Sidebar from "./Sidebar";

export default function AppLayout({
  children,
  title,
  subtitle,
}) {
  return (
    <div className="min-h-screen bg-obsidian-950 text-white flex">

      {/* Sidebar */}
      <Sidebar />

      {/* Main Content */}
      <main className="flex-1 ml-64 px-10 py-8 overflow-y-auto">

        {/* Header */}
        <div className="flex items-start justify-between mb-10">

          <div>
            <h1 className="text-5xl font-display font-bold text-white">
              {title}
            </h1>

            {subtitle && (
              <p className="text-gray-400 mt-3 text-lg max-w-3xl">
                {subtitle}
              </p>
            )}
          </div>

          {/* User Section */}
          <div className="text-right">
            <p className="text-gray-500 text-sm">
              Good evening,
            </p>

            <h2 className="text-2xl font-semibold mt-1">
              Founder
            </h2>
          </div>

        </div>

        {/* Page Content */}
        {children}

      </main>
    </div>
  );
}
